var inputItem = $input.first() || {};
var sourceJson = inputItem.json || {};
var sourceBinary = inputItem.binary || {};
var binaryKeys = Object.keys(sourceBinary);
var pdfKey = null;
for (var index = 0; index < binaryKeys.length; index += 1) {
  var file = sourceBinary[binaryKeys[index]] || {};
  var fileName = String(file.fileName || '').toLowerCase();
  var mimeType = String(file.mimeType || '').toLowerCase();
  if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
    pdfKey = binaryKeys[index];
    break;
  }
}
if (!pdfKey) {
  throw new Error('The webhook request did not include a PDF file.');
}
var duplicateMode = String(sourceJson.duplicate_mode || sourceJson.duplicateMode || sourceJson['Duplicate Mode'] || 'overwrite').toLowerCase();
if (['skip', 'overwrite'].indexOf(duplicateMode) === -1) {
  duplicateMode = 'overwrite';
}
return [{
  json: {
    source_filename: sourceJson.source_filename || sourceBinary[pdfKey].fileName || 'webhook-upload.pdf',
    ingestion_channel: 'webhook',
    received_date: sourceJson.received_date || sourceJson.receivedDate || null,
    duplicate_mode: duplicateMode,
    persist_result: !(sourceJson.persist_result === false || sourceJson.persist_result === 'false'),
    persistence_mode: sourceJson.persistence_mode === 'none' ? 'none' : 'postgres'
  },
  binary: {
    pdf: sourceBinary[pdfKey]
  }
}];
